import 'package:flutter/material.dart';import 'package:smart_scanner/core/theme/app_theme.dart';import 'package:smart_scanner/core/utils/app_date_formatter.dart';import 'package:smart_scanner/features/file_list/domain/entities/scan_file_entry.dart';import 'package:smart_scanner/features/file_list/presentation/utils/file_display_formatter.dart';class FileMetadataCard extends StatelessWidget {  const FileMetadataCard({super.key, required this.entry});  final ScanFileEntry entry;  @override  Widget build(BuildContext context) {    return Padding(      padding: const EdgeInsets.fromLTRB(20, 16, 20, 12),      child: Container(        padding: const EdgeInsets.all(16),        decoration: BoxDecoration(          color: AppTheme.fileListCard,          borderRadius: BorderRadius.circular(12),        ),        child: Column(          crossAxisAlignment: CrossAxisAlignment.start,          children: [            const Text(              'Inspection List',              style: TextStyle(                color: Colors.white,                fontWeight: FontWeight.w700,                fontSize: 16,              ),            ),            const SizedBox(height: 6),            Text(              AppDateFormatter.fileListTile.format(entry.modifiedAt),              style: const TextStyle(                color: AppTheme.fileListSubtitle,                fontSize: 13,              ),            ),            const SizedBox(height: 8),            Text(              '${entry.rowCount} items • ${FileDisplayFormatter.formatFileSize(entry.sizeInBytes)}',              style: const TextStyle(                color: AppTheme.fileListSubtitle,                fontSize: 13,              ),            ),          ],        ),      ),    );  }}